+// transactionalReloadStatus is intentionally best-effort: a bad status file must
+// never interfere with starting Prometheus or applying a configuration.
+type transactionalReloadStatus struct {
+	mu       sync.RWMutex
+	path     string
+	status   api_v1.ReloadStatus
+	lastGood *config.Config
+}
+
+func newTransactionalReloadStatus(path string) *transactionalReloadStatus {
+	s := &transactionalReloadStatus{path: path, status: api_v1.ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}}
+	b, err := os.ReadFile(path)
+	if err == nil {
+		var persisted api_v1.ReloadStatus
+		if json.Unmarshal(b, &persisted) == nil && validReloadCategory(persisted.ErrorCategory) {
+			if persisted.AppliedReloaders == nil { persisted.AppliedReloaders = []string{} }
+			if persisted.ReloaderTimingsMS == nil { persisted.ReloaderTimingsMS = map[string]int64{} }
+			s.status = persisted
+		}
+	}
+	return s
+}
+
+func validReloadCategory(category string) bool {
+	return category == "none" || category == "load_error" || category == "apply_error" || category == "rollback_error"
+}
+
+func (s *transactionalReloadStatus) Get() api_v1.ReloadStatus {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	result := s.status
+	result.AppliedReloaders = append([]string(nil), s.status.AppliedReloaders...)
+	result.ReloaderTimingsMS = make(map[string]int64, len(s.status.ReloaderTimingsMS))
+	for k, v := range s.status.ReloaderTimingsMS { result.ReloaderTimingsMS[k] = v }
+	return result
+}
+
+func (s *transactionalReloadStatus) SetLastGood(cfg *config.Config) {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	s.lastGood = cfg
+}
+
+func (s *transactionalReloadStatus) record(status api_v1.ReloadStatus) {
+	s.mu.Lock()
+	s.status = status
+	b, err := json.Marshal(status)
+	if err == nil {
+		_ = os.MkdirAll(filepath.Dir(s.path), 0o755)
+		_ = os.WriteFile(s.path+".tmp", b, 0o644)
+		_ = os.Rename(s.path+".tmp", s.path)
+	}
+	s.mu.Unlock()
+}
+
