+	if !transactional { return reloadConfig(filename, enableExemplarStorage, logger, noStepSubqueryInterval, callback, rls...) }
+	return reloadConfigTransactionally(status, filename, enableExemplarStorage, logger, noStepSubqueryInterval, callback, rls...)
+}
+
+func reloadConfigTransactionally(statusStore *transactionalReloadStatus, filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
+	status := api_v1.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339), ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+	defer func() {
+		status.LastReloadSuccessful = err == nil
+		if err == nil { configSuccess.Set(1); configSuccessTime.SetToCurrentTime(); callback(true) } else { configSuccess.Set(0); callback(false) }
+		statusStore.record(status)
+	}()
+
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		status.ErrorCategory, status.ErrorMessage = "load_error", err.Error()
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil { conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig }
+
+	for _, rl := range rls {
+		start := time.Now()
+		err = rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = time.Since(start).Milliseconds()
+		if err == nil { status.AppliedReloaders = append(status.AppliedReloaders, rl.name); continue }
+
+		status.ErrorCategory, status.ErrorMessage, status.FailedReloader = "apply_error", err.Error(), rl.name
+		if len(status.AppliedReloaders) == 0 { return fmt.Errorf("applying configuration with %s: %w", rl.name, err) }
+		status.RollbackAttempted = true
+		statusStore.mu.RLock()
+		lastGood := statusStore.lastGood
+		statusStore.mu.RUnlock()
+		if lastGood == nil { return fmt.Errorf("applying configuration with %s: %w", rl.name, err) }
+		for _, applied := range rls {
+			start := time.Now()
+			rollbackErr := applied.reloader(lastGood)
+			status.ReloaderTimingsMS["rollback_"+applied.name] = time.Since(start).Milliseconds()
+			if rollbackErr != nil {
+				status.ErrorCategory, status.ErrorMessage, status.RollbackSuccessful = "rollback_error", rollbackErr.Error(), false
+				return fmt.Errorf("applying configuration with %s: %w; rolling back %s: %w", rl.name, err, applied.name, rollbackErr)
+			}
+		}
+		status.RollbackSuccessful = true
+		return fmt.Errorf("applying configuration with %s: %w", rl.name, err)
+	}
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	statusStore.SetLastGood(conf)
+	return nil
